            // Check Choice 1: nums2[i] = nums1[i]
            if (p_i === targetParity) {
                continue; // Found a valid choice for i
            }

            // Check Choice 2: nums2[i] = nums1[i] - nums1[j], j != i
            let foundSubtractionMatch = false;
            for (let j = 0; j < n; j++) {
                if (i === j) continue;

                const p_j = nums1[j] % 2;
                // Parity of nums1[i] - nums1[j]
                const subtractionParity = (p_i - p_j + 2) % 2; 

